import streamlit as stimport pandas as pdcol1, col2 = st.columns([1, 5])with col1:    st.image("logo.png", width=80)with col2:    st.markdown("<h1>⚽ FIFA World Cup 2026 ⚽</h1>", unsafe_allow_html=True)# Sidebarpage = st.sidebar.selectbox("Izaberi stranicu:", ["Poredak", "Prethodni osvajači", "Početne predikcije"])if page == "Poredak":    df = pd.read_csv("players.csv", header=None, encoding='utf-8-sig')    df.columns = ["**Igrači**", "**Bodovi**"]    df = df.sort_values("**Bodovi**", ascending=False).reset_index(drop=True)    df.insert(2, "**Pozicija**", range(1, len(df)+1))    st.markdown("<h3 style='text-align: center;'>🏆 Poredak</h3>", unsafe_allow_html=True)    # --- Centriraj i prikaži statičnu tablicu ---    df_styled = df.style.set_properties(**{'text-align': 'center'})    st.table(df_styled)        with st.expander("📜 Pravila"):        st.write("""        - Pogođen prvak: **8 bodova**          - Pogođen viceprvak: **6 bodova**        - Pogođen igrač s najviše postignutih golova: **5 bodova**        - Pogođen igrač s najviše asistencija: **5 bodova**        - Pogođena reprezentacija koja osvaja grupnu fazu: **3 boda**        - Pogođena reprezentacija koja prolazi dalje kao druga u grupi: **3 boda**        - Pogođen igrač koji osvaja takmičenje između nas: **5 bodova (dozvoljeno klađenje na samoga sebe)**        - U slučaju pogođenog prolaska obe ekipe u grupnoj fazi, ali obrnutim redosledom: **2 boda (bod za svaku ekipu)**        - Pogođen ishod uatkmice (1, x, 2): **2 boda**        - U slučaju da pogođeni igrač s najviše postignutih golova/asistencija deli prvo mesto s nekim drugim igračem: **2 boda**        - Svoje tipove šaljete 24h prije početka prve utakmice koja označava početak novog ciklusa        """)            with st.expander("💰 Nagrade"):            st.write("""            - Pobednik dobiva nagradu u iznosu od **200 eura** + potpisani dres (**Dion Drena Beljo - GNK Dinamo Zagreb**) i dužan je organizirati večeru u roku od mesec dana od završetka prvenstva. Plaća kaznu u iznosu od **20 eura po osobi** koja se ne pojavi na večeri. Prihodi od kazne idu u nagradni fond za sledeće prvenstvo.            """)                elif page == "Prethodni osvajači":    st.markdown("<h3 style='text-align: center;'>🏆 Prethodni osvajači</h3>", unsafe_allow_html=True)    # --- Prvo prvenstvo ---    col1, col2 = st.columns([1, 3])    with col1:        st.image("cirkan.jpg", width=150)    with col2:        st.markdown("""        ### 🥇 World Cup 2022        Pobednik: **Ćirkan**                Prvo takmičenje se uvek pamti, odneo ga je majstor sa 71 bodom, koji je neretko slao tipove na salvetama i papirićima koje su mu konobari dali.        """)    st.markdown("---")    # --- Drugo prvenstvo ---    col1, col2 = st.columns([1, 3])    with col1:        st.image("organizator.jpg", width=150)    with col2:        st.markdown("""        ### 🥇 Euro 2024        Pobednik: **Organizator**                Takmičenje koje je obeleženo s dosta kontroverznih istupa poraženog Pantera, koji jednostavno nije mogao prihvatiti novo pravilo, a to je bilo tipovanje na pobednika između sebe. Organizator se tu najbolje snašao.        """)elif page == "Početne predikcije":    df_round = pd.read_csv("predikcije_igraci.csv", header=None, encoding='utf-8-sig')    df_round.columns = ["**Igrači**", "**Prvak**", "**Viceprvak**", "**Strelac**", "**Asistent**", "Pobednik takmičenja"]    st.markdown("<h3 style='text-align: center;'>📊 Igrači</h3>", unsafe_allow_html=True)    df_round_styled = df_round.style.set_properties(**{'text-align': 'center'})    st.table(df_round_styled)            df_round = pd.read_csv("predikcije_grupe.csv", header=None, encoding='utf-8-sig')    df_round.columns = ["**Igrači**", "**Grupa A**", "**Grupa B**", "**Grupa C**", "**Grupa D**", "**Grupa E**", "**Grupa F**", "**Grupa G**", "**Grupa H**", "**Grupa I**","**Grupa J**","**Grupa K**", "**Grupa L**"]    st.markdown("<h3 style='text-align: center;'>📊 Grupe</h3>", unsafe_allow_html=True)    df_round_styled = df_round.style.set_properties(**{'text-align': 'center'})    st.table(df_round_styled)                        